SELECT id, user_id, username, operation, module, method, params, result, ip, user_agent, execute_time, status, error_message, create_time
FROM system_log
WHERE 1=1

    AND module = #{type}


    AND create_time >= #{startDate}


    AND create_time <= #{endDate}

ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM system_log
WHERE 1=1

    AND module = #{type}


    AND create_time >= #{startDate}


    AND create_time <= #{endDate}
